noncompliant:
// Noncompliant: Accessing non-static member in catch block
class A {
public:
    int i;
    static int staticVar;

    A() try {
        // Constructor code that might throw
    } catch (...) {
        if (i == 0) {  // Noncompliant: i has been destroyed
            // handle error
        }
    }

    ~A() try {
        // Destructor code that might throw
    } catch (...) {
        if (i == 0) {  // Noncompliant: accessing destroyed member
            // handle error
        }
    }
};

compliant:
// Compliant: Only accessing static members or external variables
class A {
public:
    int i;
    static int staticVar;

    A() try {
        // Constructor code that might throw
    } catch (...) {
        if (staticVar == 0) {  // Compliant: static member is accessible
            // handle error
        }
        // Or use external logging
        std::cerr << "Constructor failed\n";
    }

    ~A() try {
        // Destructor code that might throw
    } catch (...) {
        // Compliant: only using static or external resources
        staticVar = -1;
        std::cerr << "Destructor failed\n";
    }
};

int A::staticVar = 0;
